namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = "";
    public string Title { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 4, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events, societies, and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and education. She specializes in programming pedagogy and introductory CS curricula.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", Title = "Data Structures & Algorithms", Code = "CS 201", Description = "In-depth study of data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization and competitive programming. He has published over 40 papers in top conferences.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", Title = "Database Systems", Code = "CS 340", Description = "Relational database design, SQL, transaction processing, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. Her research spans distributed databases and query optimization.", IsFeatured = false },
        new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students regardless of background.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", Title = "Linear Algebra", Code = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to computer graphics and data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Zhang", InstructorBio = "Dr. Zhang's research lies at the intersection of pure mathematics and machine learning applications.", IsFeatured = false },
        new() { Id = 6, DepartmentId = 3, DepartmentCode = "ENG", Title = "Academic Writing", Code = "ENG 101", Description = "Develop clear, effective writing skills for academic contexts. Focus on thesis development, argumentation, and research methods.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. David Miller", InstructorBio = "Prof. Miller has authored three textbooks on composition and rhetoric and mentors graduate writing tutors.", IsFeatured = false },
        new() { Id = 7, DepartmentId = 3, DepartmentCode = "ENG", Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period to the present day, examining cultural and historical context.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has received multiple teaching excellence awards.", IsFeatured = true },
        new() { Id = 8, DepartmentId = 4, DepartmentCode = "PHYS", Title = "General Physics I", Code = "PHYS 201", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a former NASA researcher whose work on fluid dynamics has been cited over 500 times.", IsFeatured = false },
        new() { Id = 9, DepartmentId = 4, DepartmentCode = "PHYS", Title = "Quantum Mechanics", Code = "PHYS 401", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, and hydrogen atom.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma conducts cutting-edge research in quantum computing and was recently awarded the NSF CAREER grant.", IsFeatured = false },
        new() { Id = 10, DepartmentId = 5, DepartmentCode = "HIST", Title = "World History to 1500", Code = "HIST 101", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Thomas Okafor", InstructorBio = "Dr. Okafor is an expert in ancient trade networks and has led archaeological expeditions in West Africa.", IsFeatured = false },
        new() { Id = 11, DepartmentId = 5, DepartmentCode = "HIST", Title = "Modern European History", Code = "HIST 310", Description = "Europe from the Enlightenment to the present: revolutions, industrialization, world wars, and the European Union.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Claire Dupont", InstructorBio = "Dr. Dupont specializes in French political history and has published extensively on post-war European integration.", IsFeatured = true },
    ];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

