@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses, instructors..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = CatalogService.SearchCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Title</h1>
    <span class="badge bg-secondary fs-6 mb-3">@course.Code</span>

    <div class="row mt-4">
        <div class="col-md-8">
            <h3>Description</h3>
            <p>@course.Description</p>

            <h3 class="mt-4">Instructor</h3>
            <h5>@course.InstructorName</h5>
            <p>@course.InstructorBio</p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li class="mb-2"><strong>Credits:</strong> @course.Credits</li>
                        <li class="mb-2"><strong>Schedule:</strong> @course.Schedule</li>
                        <li class="mb-2"><strong>Department:</strong> @course.DepartmentCode</li>
                    </ul>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Request Enrollment</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
        <a href="courses" class="btn btn-primary">Back to Catalog</a>
    </div>
}
else
{
    if (validationError)
    {
        <div class="alert alert-danger">Please fill in all required fields and select a course.</div>
    }

    <form method="post" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required placeholder="e.g. STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in CatalogService.GetAllCourses())
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code – @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

